# -*- coding: utf-8 -*-
import requests
import json
import sys

def search_notes(keyword):
    try:
        payload = {
            "keyword": keyword,
            "filters": {
                "sort_by": "综合",
                "note_type": "不限",
                "publish_time": "不限"
            }
        }
        resp = requests.post(
            "http://localhost:18060/api/v1/feeds/search",
            json=payload,
            timeout=60
        )
        data = resp.json()

        if data.get("success"):
            feeds = data.get("data", {}).get("feeds", [])
            print(f"Found {len(feeds)} notes for '{keyword}':\n", flush=True)

            for i, feed in enumerate(feeds[:10], 1):
                note_card = feed.get("noteCard", {})
                user = note_card.get("user", {})
                interact = note_card.get("interactInfo", {})

                title = note_card.get('displayTitle', 'No title')
                author = user.get('nickname', 'Unknown')
                likes = interact.get('likedCount', '0')

                line = f"[{i}] {title} | Author: {author} | Likes: {likes} | ID: {feed.get('id')}"
                print(line, flush=True)
        else:
            print(f"Search failed: {data.get('error', 'Unknown error')}", flush=True)

        return data
    except Exception as e:
        print(f"Error: {e}", flush=True)

if __name__ == "__main__":
    search_notes("西安教室出租")

